$(document).ready(function(){$("[data-toggle-section]").on("click",function(){var t=$(this).attr("data-toggle-section");$("[data-toggle-section]").hasClass("bg_active")&&($("[data-toggle-section]").each(function(){$(this).removeClass("bg_active")}),$(this).addClass("bg_active")),$("[data-section]").each(function(){$(this).css({transition:"opacity 0.3s",opacity:0}),setTimeout(function(){$(this).addClass("hidden")}.bind(this),300)});var i=$('[data-section="'+t+'"]');i.length&&setTimeout(function(){i.removeClass("hidden"),i.css({transition:"opacity 0.3s",opacity:0}),setTimeout(function(){i.css("opacity",1)},10)},300)})});